+    function countMatches(source, pattern) {
+      const matches = source.match(pattern);
+      return matches ? matches.length : 0;
+    }
+
     function escapeHtml(value) {
       return value
         .replace(/&/g, "&amp;")
         .replace(/</g, "&lt;")
         .replace(/>/g, "&gt;");
     }

+    function highlightDiagramSource(source) {
+      return escapeHtml(source)
+        .replace(/^%%.*$/gm, (match) => `<span class="token-comment">${match}</span>`)
+        .replace(/\b(flowchart|graph|sequenceDiagram|classDiagram|stateDiagram-v2|erDiagram|gantt|journey|timeline|pie|gitGraph|subgraph|section|participant|actor|class|state|title|dateFormat|branch|checkout|merge|commit)\b/g, '<span class="token-keyword">$1</span>')
+        .replace(/\b(TD|TB|BT|LR|RL)\b/g, '<span class="token-directive">$1</span>')
+        .replace(/(\-\->|\-\.\->|==>|-->|->>|-->>|==>|:::|:)/g, '<span class="token-arrow">$1</span>')
+        .replace(/(\[[^\]]+\]|\([^)]+\)|\{[^}]+\}|\"[^\"]+\")/g, '<span class="token-literal">$1</span>')
+        .replace(/\b([A-Z][A-Za-z0-9_]*)\b/g, '<span class="token-node">$1</span>');
+    }
+
+    function summarizeStructure(source) {
+      const lines = source.split("\n");
+      const family = currentSample?.category || "custom";
+      const nodeRefs = countMatches(source, /\b[A-Z][A-Za-z0-9_]*\b/g);
+      const arrows = countMatches(source, /(-->|==>|->>|-->>|-.->)/g);
+      const subgraphs = countMatches(source, /\bsubgraph\b/g);
+      const sections = countMatches(source, /\bsection\b/g);
+      const participants = countMatches(source, /\b(participant|actor)\b/g);
+      const comments = countMatches(source, /^%%.*$/gm);
+      const firstLine = lines[0] || "";
+
+      return [
+        `family: ${family}`,
+        `header: ${firstLine || "(empty source)"}`,
+        `lines: ${lines.length}`,
+        `node-like labels: ${nodeRefs}`,
+        `edge operators: ${arrows}`,
+        `subgraphs: ${subgraphs}`,
+        `sections: ${sections}`,
+        `participants/actors: ${participants}`,
+        `comment lines: ${comments}`,
+        "",
+        "Structural hints",
+        "---------------",
+        subgraphs > 0 ? "- This sample uses grouped subgraphs; keep branch labels short so the flow stays readable." : "- No grouped subgraphs detected; this should stay visually direct.",
+        arrows > 8 ? "- The diagram is edge-dense; decision labels and line breaks matter more than extra nodes." : "- Edge density is moderate; good candidate for quick iteration.",
+        participants > 0 ? "- Sequence-style participants are present; message verbs should stay explicit." : "- Non-sequence syntax dominates; focus on semantic grouping and labels.",
+        source.includes("%%") ? "- Comments are present; they are preserved in the authoring surface but ignored by render output." : "- No comments detected; add `%%` notes if you need author-only context."
+      ].join("\n");
+    }
+
+    function buildEditorHints(source) {
+      const hints = [];
+      if (currentSample?.label) {
+        hints.push(`${currentSample.label} baseline`);
+      }
+      if (spotlightSample?.id === currentSample?.id) {
+        hints.push("matches spotlight");
+      }
+      if (source !== (currentSample?.code || "")) {
+        hints.push("URL carries source override");
+      } else {
+        hints.push("URL can restore canonical source");
+      }
+      hints.push(`${source.split("\n").length} lines`);
+      return hints;
+    }
+
+    function syncEditorScroll() {
+      els.editorHighlight.scrollTop = els.input.scrollTop;
+      els.editorHighlight.scrollLeft = els.input.scrollLeft;
+      els.editorGutter.scrollTop = els.input.scrollTop;
+    }
+
+    function updateEditorChrome() {
+      const source = els.input.value || "";
+      const lines = source.split("\n");
+      els.editorGutter.textContent = lines.map((_, index) => String(index + 1)).join("\n");
+      els.editorHighlight.innerHTML = `${highlightDiagramSource(source)}\n`;
+      els.editorStructure.textContent = summarizeStructure(source);
+      els.editorMeta.textContent = `${currentSample?.label || "Custom source"} · ${lines.length} lines · ${source.length} chars`;
+      els.editorFamilyChip.className = `pill ${badgeClass((currentSample?.description || "").toLowerCase().includes("implemented") ? "implemented" : "partial")} rounded-full px-3 py-1 text-[11px] font-semibold uppercase tracking-[0.18em]`;
+      els.editorFamilyChip.textContent = currentSample?.category || "custom";
+      els.editorHints.innerHTML = buildEditorHints(source)
+        .map((hint) => `<span class="pill rounded-full px-3 py-1 text-[11px] font-semibold tracking-[0.14em] text-slate-200">${escapeHtml(hint)}</span>`)
+        .join("");
+      syncEditorScroll();
+    }
+
+    function setCurrentSample(sample, options = {}) {
+      const { pushHistory = false, render = true, syncInput = true } = options;
+      currentSample = sample;
+      if (syncInput) {
+        els.input.value = sample.code;
+      }
+      updateActiveSample();
+      updateEditorChrome();
+      if (pushHistory) {
+        syncUrlState("push");
+      }
+      if (render) {
+        renderAll();
+      }
+    }
+
+    function cycleEditorSample(direction) {
+      const list = editorSamples;
+      const currentIndex = list.findIndex((entry) => entry.id === currentSample.id);
+      const nextIndex = currentIndex === -1
+        ? 0
+        : (currentIndex + direction + list.length) % list.length;
+      const nextSample = list[nextIndex];
+      setCurrentSample(nextSample, { pushHistory: true, render: true, syncInput: true });
+    }
